// Browse AIからのデータ整形
const input = $input.first().json.body || $input.first().json;

// データ抽出
const robotName = input.robot?.name || input.robotName || 'unknown';
const url = input.capturedAt?.url || input.url || '';
const extractedData = input.extractedData || input.data || {};
const timestamp = input.capturedAt?.timestamp || new Date().toISOString();

// 重要度スコア計算
function calculateImportance(data, robotName) {
  let score = 0;

  // セール情報: 高重要度
  if (robotName.includes('Sale') || robotName.includes('セール')) {
    if (data.salePrice || data.discount) score += 10;
    if (data.price && data.originalPrice) score += 8;
  }

  // トレンド情報: 中重要度
  if (robotName.includes('Trending') || robotName.includes('トレンド')) {
    if (data.stars || data.starCount) score += 5;
    if (data.trending) score += 5;
  }

  // 競合変更: 高重要度
  if (robotName.includes('Competitor') || robotName.includes('競合')) {
    if (data.changes || data.diff) score += 8;
    score += 5; // 競合は常に重要
  }

  return score;
}

const importance = calculateImportance(extractedData, robotName);

// メッセージ生成
function generateMessage(robotName, data, importance) {
  let message = `🔍 **${robotName}** から新しい情報を検出\n\n`;

  if (robotName.includes('Sale')) {
    message += `💰 **セール情報**\n`;
    if (data.name) message += `商品: ${data.name}\n`;
    if (data.price) message += `価格: ${data.price}\n`;
    if (data.discount) message += `割引: ${data.discount}\n`;
    if (data.link) message += `リンク: ${data.link}\n`;
  } else if (robotName.includes('Trending')) {
    message += `📈 **トレンド情報**\n`;
    if (data.name) message += `リポジトリ: ${data.name}\n`;
    if (data.stars) message += `⭐ ${data.stars} stars\n`;
    if (data.language) message += `言語: ${data.language}\n`;
  } else if (robotName.includes('Competitor')) {
    message += `🕵️ **競合サイト変更**\n`;
    message += `URL: ${url}\n`;
    if (data.changes) message += `変更内容: ${JSON.stringify(data.changes)}\n`;
  }

  message += `\n重要度スコア: ${importance}/20`;

  return message;
}

const message = generateMessage(robotName, extractedData, importance);

return [{
  json: {
    robotName,
    url,
    extractedData,
    timestamp,
    importance,
    message,
    shouldNotify: importance >= 5
  }
}];

